document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector('input[name="csrf_token"]')?.value,t=async(e,t)=>(await fetch(`${window.BASE_URL}${e}`,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams(t)})).json();function a(e,t="success"){const a=document.createElement("div");a.className=`toast-notification alert alert-${t}`,a.textContent=e,document.body.appendChild(a),setTimeout(()=>a.remove(),3e3)}document.querySelectorAll(".status-select").forEach(s=>{s.addEventListener("change",async()=>{const n=s.dataset.id,c=s.value,o=await t("/admin/agenda/status",{id:n,status:c,csrf_token:e});o.success?a("Status atualizado com sucesso!","success"):a(o.message,"danger")})}),document.querySelectorAll(".btn-delete").forEach(s=>{s.addEventListener("click",async()=>{if(!confirm("Deseja realmente excluir este agendamento?"))return;const n=s.dataset.id;(await t("/admin/agenda/excluir",{id:n,csrf_token:e})).success&&(s.closest("tr").remove(),a("Agendamento excluído.","success"))})}),document.getElementById("block-form")?.addEventListener("submit",async e=>{e.preventDefault();const s=new FormData(e.target),n=await t("/admin/agenda/bloquear-data",Object.fromEntries(s));n.success&&(a(n.message,"success"),setTimeout(()=>window.location.reload(),800))}),document.querySelectorAll(".btn-unblock").forEach(a=>{a.addEventListener("click",async()=>{const s=a.dataset.id;(await t("/admin/agenda/desbloquear-data",{id:s,csrf_token:e})).success&&a.closest("li").remove()})})});